import{_ as t,o as l,c as e,a2 as i}from"./chunks/framework.Bjylvv1V.js";const g=JSON.parse('{"title":"검침 처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/meter-reading.md","filePath":"guide/scenarios/meter-reading.md","lastUpdated":1771991831000}'),r={name:"guide/scenarios/meter-reading.md"};function o(s,a,n,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="검침-처리" tabindex="-1">검침 처리 <a class="header-anchor" href="#검침-처리" aria-label="Permalink to &quot;검침 처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 1~2시간 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 매월 1~2주차</p></blockquote><p>각 세대의 계량기(전기·수도·온수·가스·난방)를 검침하여 사용량을 산정하는 프로세스입니다. 검침 데이터는 관리비 부과의 기초가 됩니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 전월 지침 불러오기   (1분)  → 전월 데이터 로드</span></span>
<span class="line"><span>2. 당월 지침 입력       (30분~) → 세대별 검침값 입력</span></span>
<span class="line"><span>3. 요금 계산           (3분)  → 사용량·요금 자동 계산</span></span>
<span class="line"><span>4. 이상값 확인         (5분)  → 비정상 사용량 점검</span></span>
<span class="line"><span>5. 저장               (1분)  → 확정 저장</span></span>
<span class="line"><span>───── 위 과정을 전기·수도·온수·가스·난방 각각 반복 ─────</span></span></code></pre></div><hr><h2 id="검침-종류-및-순서" tabindex="-1">검침 종류 및 순서 <a class="header-anchor" href="#검침-종류-및-순서" aria-label="Permalink to &quot;검침 종류 및 순서&quot;">​</a></h2><table tabindex="0"><thead><tr><th>순서</th><th>검침 항목</th><th>메뉴 경로</th><th>화면 코드</th></tr></thead><tbody><tr><td>1</td><td>전기검침</td><td><a href="/insp/">검침</a> &gt; <a href="/insp/electric.html">전기검침</a></td><td>INSP1120</td></tr><tr><td>2</td><td>수도검침</td><td><a href="/insp/">검침</a> &gt; <a href="/insp/water.html">수도검침</a></td><td>INSP2110</td></tr><tr><td>3</td><td>온수검침</td><td><a href="/insp/">검침</a> &gt; <a href="/insp/hot-water.html">온수검침</a></td><td>-</td></tr><tr><td>4</td><td>가스검침</td><td><a href="/insp/">검침</a> &gt; <a href="/insp/gas.html">가스검침</a></td><td>-</td></tr><tr><td>5</td><td>난방검침</td><td><a href="/insp/">검침</a> &gt; <a href="/insp/heating.html">난방검침</a></td><td>-</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">순서가 중요한가요?</p><p>검침 항목 간 순서는 자유입니다. 다만 <strong>모든 검침을 완료한 후</strong>에 관리비 부과를 진행해야 합니다.</p></div><hr><h2 id="전기검침-상세-절차-대표-예시" tabindex="-1">전기검침 상세 절차 (대표 예시) <a class="header-anchor" href="#전기검침-상세-절차-대표-예시" aria-label="Permalink to &quot;전기검침 상세 절차 (대표 예시)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 검침 &gt; <a href="/insp/electric.html">전기검침</a> (INSP1120)</p></blockquote><p>다른 검침(수도·온수·가스·난방)도 동일한 패턴으로 진행됩니다.</p><h3 id="_1단계-전월-지침-불러오기" tabindex="-1">1단계: 전월 지침 불러오기 <a class="header-anchor" href="#_1단계-전월-지침-불러오기" aria-label="Permalink to &quot;1단계: 전월 지침 불러오기&quot;">​</a></h3><ol><li>전기검침 화면 진입</li><li><strong>부과 연월</strong> 선택 (예: 2026-03)</li><li><strong>구역</strong> 선택 (해당되는 경우)</li><li><strong>전월지침</strong> 버튼 클릭 → 전월 데이터가 자동으로 채워짐</li></ol><h3 id="_2단계-당월-지침-입력" tabindex="-1">2단계: 당월 지침 입력 <a class="header-anchor" href="#_2단계-당월-지침-입력" aria-label="Permalink to &quot;2단계: 당월 지침 입력&quot;">​</a></h3><p><strong>방법 A: 직접 입력</strong></p><ol><li>각 세대의 <strong>당월지침</strong> 칸에 계량기 숫자를 입력</li><li><strong>사용량</strong>은 자동 계산됨 (당월지침 - 전월지침)</li></ol><p><strong>방법 B: 엑셀 업로드 (대량 입력)</strong></p><ol><li>엑셀 파일 준비 (칼럼: 동, 호수, 전월지침, 당월지침, 사용량)</li><li>파일 형식: <strong>.xlsx</strong></li><li>업로드 실행</li></ol><div class="warning custom-block"><p class="custom-block-title">당월지침이 전월보다 작은 경우</p><p>계량기를 교체한 경우가 아니면 당월 지침은 전월보다 커야 합니다. 시스템이 경고를 표시하면 계량기 상태를 확인하세요.</p></div><h3 id="_3단계-요금-계산" tabindex="-1">3단계: 요금 계산 <a class="header-anchor" href="#_3단계-요금-계산" aria-label="Permalink to &quot;3단계: 요금 계산&quot;">​</a></h3><ol><li>모든 세대 입력 완료 확인</li><li><strong>요금계산</strong> 버튼 클릭</li><li>복지 구분 확인 (기초생활, 국가유공자, 장애인 등 감면 대상)</li><li>세대별 요금이 자동 계산됨 <ul><li>전기요금 = 사용량 × 단가 (구간별 차등)</li><li>TV수신료 자동 포함</li></ul></li></ol><h3 id="_4단계-이상값-확인" tabindex="-1">4단계: 이상값 확인 <a class="header-anchor" href="#_4단계-이상값-확인" aria-label="Permalink to &quot;4단계: 이상값 확인&quot;">​</a></h3><p>전월 대비 사용량이 비정상적으로 높거나 낮은 세대를 확인합니다.</p><blockquote><p><strong>메뉴 경로</strong>: 검침 &gt; <a href="/insp/electric.html">전기검침</a> &gt; 전기사용량조회 (INSP1210)</p></blockquote><ul><li>전월 대비 <strong>20% 이상</strong> 급증한 세대 → 오입력 또는 실제 사용량 증가인지 확인</li><li>사용량이 <strong>0</strong>인 세대 → 공실 또는 미입력인지 확인</li><li>마이너스 사용량 → 지침 입력 오류 가능</li></ul><h3 id="_5단계-저장" tabindex="-1">5단계: 저장 <a class="header-anchor" href="#_5단계-저장" aria-label="Permalink to &quot;5단계: 저장&quot;">​</a></h3><ol><li>이상값을 모두 확인/수정한 후 <strong>저장</strong> 클릭</li><li>저장 완료 메시지 확인</li></ol><hr><h2 id="수도검침-주의사항" tabindex="-1">수도검침 주의사항 <a class="header-anchor" href="#수도검침-주의사항" aria-label="Permalink to &quot;수도검침 주의사항&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 검침 &gt; <a href="/insp/water.html">수도검침</a> (INSP2110)</p></blockquote><ul><li>수도+온수를 <strong>묶어서 처리</strong>하는 단지가 있음 → 단지 설정 확인</li><li>지역별 감면 옵션이 있음 (경남, 경기 등) → 해당 지역이면 감면 설정 필요</li><li>복수 계량기가 있는 세대는 <strong>모든 계량기</strong> 입력 필요</li></ul><hr><h2 id="특수-상황-처리" tabindex="-1">특수 상황 처리 <a class="header-anchor" href="#특수-상황-처리" aria-label="Permalink to &quot;특수 상황 처리&quot;">​</a></h2><h3 id="계량기-교체" tabindex="-1">계량기 교체 <a class="header-anchor" href="#계량기-교체" aria-label="Permalink to &quot;계량기 교체&quot;">​</a></h3><p>계량기를 교체한 세대는:</p><ol><li>구 계량기 최종 지침 → 전월 검침에 마감</li><li>신 계량기 시작 지침 → 당월 검침에 초기값 입력</li><li>사용량 = (구 계량기 최종값 - 전월지침) + (당월지침 - 신 계량기 시작값)</li></ol><h3 id="전기-이중계량기-세대" tabindex="-1">전기 이중계량기 세대 <a class="header-anchor" href="#전기-이중계량기-세대" aria-label="Permalink to &quot;전기 이중계량기 세대&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 검침 &gt; <a href="/insp/electric.html">전기검침</a> &gt; 전기계량기2검침 (INSP1160)</p></blockquote><p>계량기가 2개인 세대는 별도로 두 번째 계량기를 입력합니다. 사용량 합산 후 구간별 요금이 적용됩니다.</p><h3 id="감면-세대-확인" tabindex="-1">감면 세대 확인 <a class="header-anchor" href="#감면-세대-확인" aria-label="Permalink to &quot;감면 세대 확인&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 검침 &gt; <a href="/insp/electric.html">전기검침</a> &gt; 전기감면세대 (INSP1240)</p></blockquote><p>TV수신료 면제, 복지 할인(기초생활·국가유공자·장애인 등) 대상 세대를 확인할 수 있습니다.</p><hr><h2 id="전체-체크리스트" tabindex="-1">전체 체크리스트 <a class="header-anchor" href="#전체-체크리스트" aria-label="Permalink to &quot;전체 체크리스트&quot;">​</a></h2><ul><li>[ ] 전기검침 완료 및 저장</li><li>[ ] 수도검침 완료 및 저장</li><li>[ ] 온수검침 완료 및 저장</li><li>[ ] 가스검침 완료 및 저장</li><li>[ ] 난방검침 완료 및 저장</li><li>[ ] 각 검침별 이상값(급증·0·마이너스) 확인 완료</li><li>[ ] 감면 세대 상태가 최신인가?</li><li>[ ] 계량기 교체 세대가 있으면 정확히 반영했는가?</li></ul><div class="tip custom-block"><p class="custom-block-title">검침 완료 후 다음 단계</p><p>모든 검침이 완료되면 <a href="/guide/scenarios/billing.html">관리비 부과</a>를 진행합니다.</p></div><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="전월지침-버튼을-눌러도-데이터가-안-나와요" tabindex="-1">전월지침 버튼을 눌러도 데이터가 안 나와요 <a class="header-anchor" href="#전월지침-버튼을-눌러도-데이터가-안-나와요" aria-label="Permalink to &quot;전월지침 버튼을 눌러도 데이터가 안 나와요&quot;">​</a></h3><p><strong>원인</strong>: 전월 검침이 저장되지 않았거나, 부과 연월 선택이 잘못된 경우 <strong>해결</strong>: 부과 연월을 정확히 선택하고, 전월 검침이 저장되어 있는지 확인하세요.</p><h3 id="요금계산-결과가-예상과-달라요" tabindex="-1">요금계산 결과가 예상과 달라요 <a class="header-anchor" href="#요금계산-결과가-예상과-달라요" aria-label="Permalink to &quot;요금계산 결과가 예상과 달라요&quot;">​</a></h3><p><strong>원인</strong>: 단가 변경, 감면 적용 누락, 구간별 요금 기준 변경 <strong>해결</strong>: 단가 설정과 감면 세대 등록을 확인하고, 한전요금조회(INSP1250)로 비교해 보세요.</p><h3 id="엑셀-업로드가-안-돼요" tabindex="-1">엑셀 업로드가 안 돼요 <a class="header-anchor" href="#엑셀-업로드가-안-돼요" aria-label="Permalink to &quot;엑셀 업로드가 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 파일 형식 오류 <strong>해결</strong>: 전기검침은 <strong>.xlsx</strong>, 다른 업로드는 <strong>Excel 97-2003(.xls)</strong> 형식을 사용해야 합니다. 칼럼 구조도 양식에 맞는지 확인하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/insp/">검침 개요</a> - 검침 전체 구조</li><li><a href="/insp/electric.html">전기검침</a> - 전기검침 상세</li><li><a href="/insp/water.html">수도검침</a> - 수도검침 상세</li><li><a href="/insp/hot-water.html">온수검침</a> - 온수검침 상세</li><li><a href="/insp/gas.html">가스검침</a> - 가스검침 상세</li><li><a href="/insp/heating.html">난방검침</a> - 난방검침 상세</li><li><a href="/guide/scenarios/billing.html">관리비 부과</a> - 검침 후 다음 단계</li></ul>`,59)])])}const u=t(r,[["render",o]]);export{g as __pageData,u as default};
